	type Trial struct {
		assignIdx int
		delta     float64
		ok        bool
	}
	const NO_TRIAL = -1
	for orderIdx := 0; orderIdx < len(oris); orderIdx++ {
		id := total_ship + orderIdx
		ori := oris[orderIdx]
		des := dess[orderIdx]
		bestTrial := Trial{assignIdx: NO_TRIAL, delta: 0, ok: false}
		baseCostBackup := make([]float64, dispatch.AssignsLen)
		stationCurrentBackup := make([]Station, dispatch.AssignsLen)
		for i := 0; i < dispatch.AssignsLen; i++ {
			baseCostBackup[i] = dispatch.Assigns[i].Cost
			stationCurrentBackup[i] = dispatch.Assigns[i].StationCurrent
		}
		for tryIdx := 0; tryIdx < dispatch.AssignsLen; tryIdx++ {
			asgn := &dispatch.Assigns[tryIdx]
			oldCost := asgn.Cost
			if oldCost < 0 {
				continue
			}
			addOk := asgn.AddShip(id, ori, des)
			if !addOk {
				continue
			}
			asgn.GenRoute()
			newCost := asgn.Cost
			if newCost < 0 || newCost < oldCost-1e-9 {
				asgn.RemoveShip(id)
				asgn.GenRoute()
				continue
			}
			delta := newCost - oldCost
			if !bestTrial.ok || delta < bestTrial.delta {
				bestTrial.assignIdx = tryIdx
				bestTrial.delta = delta
				bestTrial.ok = true
			}
			asgn.RemoveShip(id)
			asgn.GenRoute()
		}
		if bestTrial.ok {
			targetAsgn := &dispatch.Assigns[bestTrial.assignIdx]
			targetAsgn.AddShip(id, ori, des)
			targetAsgn.GenRoute()
			continue
		}
		fallbackOk := false
		if dispatch.AssignsLen < MAXASSIGNS {
			fbIdx := dispatch.AssignsLen
			asgn := &dispatch.Assigns[fbIdx]
			asgn.ResetSafe()
			if asgn.AddShip(id, ori, des) {
				asgn.GenRoute()
				if asgn.Cost >= 0 {
					dispatch.AssignsLen++
					fallbackOk = true
				} else {
					asgn.RemoveShip(id)
					asgn.GenRoute()
				}
			}
		}
		if !fallbackOk {
			insertedIntoExisting := false
			for tryIdx := 0; tryIdx < dispatch.AssignsLen; tryIdx++ {
				asgn := &dispatch.Assigns[tryIdx]
				if asgn.AddShip(id, ori, des) {
					asgn.GenRoute()
					if asgn.Cost >= 0 {
						insertedIntoExisting = true
						break
					}
					asgn.RemoveShip(id)
					asgn.GenRoute()
				}
			}
			if !insertedIntoExisting && dispatch.AssignsLen < MAXASSIGNS {
				asgn := &dispatch.Assigns[dispatch.AssignsLen]
				asgn.ResetSafe()
				if asgn.AddShip(id, ori, des) {
					asgn.GenRoute()
					if asgn.Cost >= 0 {
						dispatch.AssignsLen++
					} else {
						asgn.RemoveShip(id)
						asgn.GenRoute()
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

