					dispatch.AssignsLen++
					fallbackOk = true
				} else {
					asgn.RemoveShip(id)
					asgn.GenRoute()
				}
			}
		}
		if !fallbackOk {
			insertedIntoExisting := false
			for tryIdx := 0; tryIdx < dispatch.AssignsLen; tryIdx++ {
				asgn := &dispatch.Assigns[tryIdx]
				if asgn.AddShip(id, ori, des) {
					asgn.GenRoute()
					if asgn.Cost >= 0 {
						insertedIntoExisting = true
						break
					}
					asgn.RemoveShip(id)
					asgn.GenRoute()
				}
			}
			if !insertedIntoExisting && dispatch.AssignsLen < MAXASSIGNS {
				asgn := &dispatch.Assigns[dispatch.AssignsLen]
				asgn.ResetSafe()
				if asgn.AddShip(id, ori, des) {
					asgn.GenRoute()
					if asgn.Cost >= 0 {
						dispatch.AssignsLen++
					} else {
						asgn.RemoveShip(id)
						asgn.GenRoute()
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch
}
